text(JSON.stringify(relevant, null, 2));

const pwd = "/Users/zchee/go/src/github.com/zchee/spanner-manager";

const mem = await tools.shell_command({
  command: `python3 - <<'PY'
from pathlib import Path
base = Path("/Users/zchee/src/github.com/zchee/dotfiles/.config/codex/memories")
mem = base/"MEMORY.md"
keywords = ["spanner-manager", "header", "codegen", "gofumpt", "quality"]
text = mem.read_text()
for i, line in enumerate(text.splitlines(), 1):
    if any(k.lower() in line.lower() for k in keywords):
        start=max(1,i-2); end=min(len(text.splitlines()), i+2)
        print(f"--- hit around line {i} ---")
        for j in range(start,end+1):
            print(f"{j}:{text.splitlines()[j-1]}")
PY`,
  workdir: pwd,
  timeout_ms: 10000,
});
text("\nMEMORY SEARCH\n"+mem.stdout);

const diff = await tools.shell_command({
  command: `git status --short && echo '\n--- DIFF ---' && git diff --stat && echo '\n--- FULL DIFF ---' && git diff --`,
  workdir: pwd,
  timeout_ms: 20000,
});
text("\nGIT\n"+diff.stdout);

