package main

import (
	"os"
	"path/filepath"

	"github.com/zchee/spanner-manager/codegen"
)

func main() {
	root, err := os.MkdirTemp("", "codegen-repro-")
	if err != nil {
		panic(err)
	}
	templateDir := filepath.Join(root, "templates")
	outDir := filepath.Join(root, "models")
	if err := os.MkdirAll(templateDir, 0o755); err != nil {
		panic(err)
	}
	files := map[string]string{
		"header.go.tmpl": "{{- define \\"header\\" -}}\\npackage {{ .PackageName }}\\nconst HeaderOverrideMarker = \\"header override\\"\\n{{ end -}}\\n",
		"spanner_db.go.tmpl": "{{ template \\"header\\" . }}\\n\\ntype SpannerDB interface{}\\nvar SpannerLog = func(...any) {}\\n",
		"type.go.tmpl": "{{ template \\"header\\" . }}\\n\\ntype {{ .Type.Name }} struct{}\\n",
	}
	for name, content := range files {
		if err := os.WriteFile(filepath.Join(templateDir, name), []byte(content), 0o644); err != nil {
			panic(err)
		}
	}
	schema := &codegen.Schema{Types: []codegen.Type{{Name: "Users", Table: "Users", Fields: []codegen.Field{{Name: "ID", ColumnName: "id", GoType: "int64", SpannerType: "INT64", BaseSpannerType: "INT64", NotNull: true, IsPrimaryKey: true}}}}}
	if err := codegen.NewGenerator(codegen.Options{OutDir: outDir, PackageName: "models", TemplatePath: templateDir}).Generate(schema); err != nil {
		panic(err)
	}
	println(outDir)
}
EOF

